class SimpleDBMS:
    def __init__(self):
        self.data = {}
        self.data_dictionary = {}
        self.transaction_log = []
        self.buffer = {}

    def create_table(self, table_name, schema):
        """DDL: Create table with schema definition"""
        self.data[table_name] = []
        self.data_dictionary[table_name] = schema
        print(f"Table {table_name} created with schema: {schema}")

    def insert(self, table_name, record):
        """DML: Insert record into table"""
        # Validate against schema
        schema = self.data_dictionary[table_name]
        for key in schema:
            if key not in record:
                raise ValueError(f"Missing required field: {key}")

        # Transaction logging for recovery
        self.transaction_log.append(("INSERT", table_name, record))
        self.data[table_name].append(record)
        print(f"Record inserted into {table_name}")

    def select(self, table_name, condition=None):
        """Query: Retrieve data with optional condition"""
        records = self.data[table_name]
        if condition:
            return [r for r in records if condition(r)]
        return records

    def commit(self):
        """Transaction commit - flush log to permanent storage"""
        print("Transaction committed successfully")
        self.transaction_log.clear()

    def rollback(self):
        """Transaction rollback - undo recent operations"""
        for operation in reversed(self.transaction_log):
            if operation[0] == "INSERT":
                self.data[operation[1]].remove(operation[2])
        print("Transaction rolled back")
        self.transaction_log.clear()

