// Simulating DBMS buffer management
#define BUFFER_SIZE 100

typedef struct {
    int page_id;
    char data[256];
    int is_dirty;  // Modified flag
    int pin_count; // For concurrency control
} BufferFrame;

BufferFrame buffer_pool[BUFFER_SIZE];

// Initialize buffer pool
void init_buffer() {
    for (int i = 0; i < BUFFER_SIZE; i++) {
        buffer_pool[i].page_id = -1;
        buffer_pool[i].is_dirty = 0;
        buffer_pool[i].pin_count = 0;
    }
}

// Find page in buffer (Buffer Manager)
int find_in_buffer(int page_id) {
    for (int i = 0; i < BUFFER_SIZE; i++) {
        if (buffer_pool[i].page_id == page_id) {
            return i;  // Return buffer frame index
        }
    }
    return -1;  // Not in buffer
}

// Get page (with buffer management)
BufferFrame* get_page(int page_id) {
    int frame_idx = find_in_buffer(page_id);

    if (frame_idx != -1) {
        // Page found in buffer
        buffer_pool[frame_idx].pin_count++;
        return &buffer_pool[frame_idx];
    } else {
        // Need to load from disk
        // In real DBMS: call Storage Manager
        for (int i = 0; i < BUFFER_SIZE; i++) {
            if (buffer_pool[i].page_id == -1) {
                buffer_pool[i].page_id = page_id;
                buffer_pool[i].pin_count = 1;
                // Simulate disk read
                printf("Loading page %d from disk to buffer\n", page_id);
                return &buffer_pool[i];
            }
        }
    }
    return NULL;  // Buffer full - needs replacement
}

// Release page (unpin)
void release_page(BufferFrame* frame) {
    if (frame->pin_count > 0)
        frame->pin_count--;
}

int main() {
    init_buffer();

    // Simulate accessing data pages
    BufferFrame* page = get_page(101);
    strcpy(page->data, "Student Record: Raj, Grade: A");
    page->is_dirty = 1;  // Mark as modified

    release_page(page);

    // Later access - should find in buffer
    page = get_page(101);
    printf("Data: %s\n", page->data);

    return 0;
}

import java.util.*;

class TransactionManager {
    private List<String> transactionLog = new ArrayList<>();
    private Map<String, Integer> locks = new HashMap<>();
    private boolean committed = false;

    // Lock management for concurrency control
    public synchronized void acquireLock(String resource, String transactionId) {
        while (locks.containsKey(resource)) {
            try {
                wait();
            } catch (InterruptedException e) {}
        }
        locks.put(resource, transactionId.hashCode());
    }

    public synchronized void releaseLock(String resource) {
        locks.remove(resource);
        notifyAll();
    }

    // Begin transaction
    public void beginTransaction(String transactionId) {
        System.out.println("Transaction " + transactionId + " started");
        transactionLog.clear();
        committed = false;
    }

    // Write operation with logging
    public void write(String transactionId, String data) {
        String logEntry = transactionId + ":WRITE:" + data;
        transactionLog.add(logEntry);
        System.out.println("Logged: " + logEntry);
    }

    // Commit - ensure all operations succeed (Atomicity & Durability)
    public synchronized boolean commit(String transactionId) {
        // Write-Ahead Logging: flush log before commit
        flushLogToDisk();

        committed = true;
        System.out.println("Transaction " + transactionId + " COMMITTED");

        // Release all locks
        locks.clear();
        return true;
    }

    // Rollback - undo all operations (Atomicity)
    public synchronized boolean rollback(String transactionId) {
        System.out.println("Rolling back transaction: " + transactionId);

        // Read log in reverse and undo each operation
        for (int i = transactionLog.size() - 1; i >= 0; i--) {
            String logEntry = transactionLog.get(i);
            if (logEntry.startsWith(transactionId)) {
                // Undo the operation
                System.out.println("Undoing: " + logEntry);
            }
        }

        transactionLog.clear();
        locks.clear();
        System.out.println("Transaction " + transactionId + " ROLLED BACK");
        return true;
    }

    private void flushLogToDisk() {
        // Simulate writing log to persistent storage
        System.out.println("Writing transaction log to disk (WAL)");
    }

    public static void main(String[] args) {
        TransactionManager tm = new TransactionManager();

        // Example transaction
        tm.beginTransaction("T1");
        tm.acquireLock("account_101", "T1");
        tm.write("T1", "Debit: $500 from account_101");
        tm.write("T1", "Credit: $500 to account_102");

        // Commit the transaction
        if (true) { // Assume all conditions met
            tm.commit("T1");
        }
    }
}

/* DBMS Transaction Properties (ACID):
 * Atomicity: All or nothing - handled by rollback
 * Consistency: Valid state transitions - enforced by constraints
 * Isolation: Concurrent transactions appear serial - locking
 * Durability: Committed data persists - write-ahead logging
 */
